1	import { useState, useEffect, useCallback, useMemo } from 'react';
2	import {
3	  AlertTriangle,
4	  ChevronRight,
5	  ExternalLink,
6	  FileText,
7	  RefreshCw,
8	  X,
9	  Save,
10	  Sparkles,
11	} from 'lucide-react';
12	import { fetchReviews, resolveReview, fetchFactSources, fetchEntity } from '../api';
13	
14	/**
15	 * Dedicated Review Queue page. Renders one row per open review_items
16	 * record, with a 2-column source-card detail per selected review.
17	 * Drives /reviews and /reviews/{id}/resolve only — no other endpoints.
18	 *
19	 * Schema (from context_base/storage.py + context_base/ingest.py):
20	 *   review_items: id, entity_id, conflict_type, predicate,
21	 *                 candidates_json, suggested_resolution, status,
22	 *                 created_at, resolved_at, resolution
23	 *   candidate    : { choice_id, fact_id, value, confidence,
24	 *                    source: "<dataset_path>#<record_id>" }
25	 *
26	 * Visual style follows the existing ui/ design system (light theme,
27	 * Inter body / JetBrains Mono mono, --accent teal anchor, --warning
28	 * amber variant) — see .rq-* block in src/index.css. The source-detail
29	 * drawer reuses the existing .source-panel class shared with App.tsx.
30	 */
31	
32	interface Candidate {
33	  choice_id: string;
34	  fact_id?: string | null;
35	  value?: string;
36	  object_entity_id?: string;
37	  confidence?: number;
38	  /** Format: "<dataset_path>#<record_id>" (see ingest.py l.730) */
39	  source?: string;
40	  snippet?: string;
41	}
42	
43	interface ReviewItem {
44	  id: string;
45	  entity_id: string;
46	  conflict_type: string;
47	  predicate: string;
48	  candidates_json: string;
49	  suggested_resolution?: string | null;
50	  status: string;
51	  created_at: string;
52	  resolved_at?: string | null;
53	  resolution?: string | null;
54	}
55	
56	interface ReviewQueueProps {
57	  /** Optional: handler to switch to the Browser view and open an entity.
58	   *  When omitted, the entity_id heading renders as plain text. */
59	  onNavigateToEntity?: (entityId: string) => void;
60	}
61	
